<template>
  <div class="qa-home">
    <div class="page-header">
      <div>
        <h2 class="page-title">智能问答</h2>
        <p class="page-subtitle">向 AI 提问编程问题，获取专业解答</p>
      </div>
    </div>

    <el-row :gutter="24">
      <!-- 提问区 -->
      <el-col :xs="24" :sm="24" :md="14">
        <div class="qa-card-main">
          <div class="qa-card-header">
            <i class="el-icon-edit"></i>
            <span>向 AI 提问</span>
          </div>
          <el-form :model="form" label-width="0">
            <el-form-item>
              <el-input v-model="form.title" placeholder="用一句话概括你的问题" class="qa-input" size="large" prefix-icon="el-icon-question" />
            </el-form-item>
            <el-form-item>
              <el-select v-model="form.category" placeholder="选择分类" class="qa-select">
                <el-option label="Java 基础" value="java-basics" />
                <el-option label="Spring 框架" value="spring" />
                <el-option label="数据库" value="database" />
                <el-option label="前端" value="frontend" />
                <el-option label="算法" value="algorithm" />
                <el-option label="工具" value="tools" />
                <el-option label="其他" value="general" />
              </el-select>
            </el-form-item>
            <el-form-item>
              <el-input type="textarea" :rows="6" v-model="form.content" placeholder="详细描述你的问题，包括代码、报错信息和期望结果..." class="qa-textarea" />
            </el-form-item>
            <el-form-item>
              <el-button type="primary" :loading="asking" class="qa-submit-btn" @click="handleAsk" :disabled="!form.title || !form.content">
                <i class="el-icon-position"></i>
                {{ asking ? 'AI 思考中...' : '发送问题' }}
              </el-button>
            </el-form-item>
          </el-form>
        </div>
      </el-col>

      <!-- 问题列表 -->
      <el-col :xs="24" :sm="24" :md="10">
        <div class="qa-card-side">
          <div class="qa-card-header">
            <i class="el-icon-tickets"></i>
            <span>最近问题 ({{ displayQuestions.length }})</span>
          </div>

          <div v-if="displayQuestions.length === 0" class="empty-state">
            <div class="empty-icon">💬</div>
            <p>暂无问题，快来提问吧</p>
          </div>

          <div v-else class="question-list">
            <div v-for="q in displayQuestions" :key="q.id" class="question-item" @click="$router.push(`/qa/${q.id}`)">
              <div class="q-left">
                <span class="q-count">{{ q.answerCount || 0 }}</span>
                <span class="q-count-label">回答</span>
              </div>
              <div class="q-right">
                <div class="q-title">
                  {{ q.title }}
                  <span v-if="q.isResolved" class="q-resolved"><i class="el-icon-success"></i></span>
                </div>
                <div class="q-meta">
                  <span class="badge badge-blue">{{ categoryLabel(q.category) }}</span>
                  <span class="q-stat"><i class="el-icon-view"></i> {{ q.viewCount || 0 }}</span>
                  <span class="q-stat"><i class="el-icon-star-off"></i> {{ q.favoriteCount || 0 }}</span>
                  <span class="q-time">{{ timeAgo(q.createTime) }}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import { qaApi } from '../api';
import { mockQuestions, fallbackArray } from '../mock';

export default {
  name: 'QaHome',
  data() {
    return {
      form: { title: '', content: '', category: 'general' },
      asking: false,
      questions: []
    };
  },
  computed: {
    displayQuestions() {
      return fallbackArray(this.questions, mockQuestions);
    }
  },
  created() { this.loadQuestions(); },
  methods: {
    async loadQuestions() {
      try {
        const res = await qaApi.getList({ page: 1, pageSize: 20 });
        if (res.code === 200) this.questions = (res.data && res.data.list) || [];
      } catch {}
    },
    async handleAsk() {
      if (!this.form.title || !this.form.content) return;
      this.asking = true;
      try {
        const res = await qaApi.ask(this.form);
        if (res.code === 200) {
          this.$message.success('提问成功，AI 正在回答...');
          this.form = { title: '', content: '', category: 'general' };
          this.$router.push(`/qa/${res.data.id}`);
        }
      } finally {
        this.asking = false;
      }
    },
    categoryLabel(c) {
      const map = {
        'java-basics': 'Java', spring: 'Spring',
        database: '数据库', frontend: '前端',
        algorithm: '算法', tools: '工具', general: '其他'
      };
      return map[c] || c;
    },
    timeAgo(time) {
      if (!time) return '';
      const diff = Date.now() - new Date(time).getTime();
      const m = Math.floor(diff / 60000);
      if (m < 1) return '刚刚';
      if (m < 60) return `${m} 分钟前`;
      const h = Math.floor(m / 60);
      if (h < 24) return `${h} 小时前`;
      const d = Math.floor(h / 24);
      if (d < 30) return `${d} 天前`;
      return new Date(time).toLocaleDateString('zh-CN');
    }
  }
};
</script>

